import React from "react";
import { imgKatie } from "../imakatie-zaferes.png";

export default function Card() {
  return (
    <div className="card">
      <img
        src="./images/katie-zaferes.png"
        className="card--image"
        alt="Katie Zaferes"
      />
      <div className="card--stats">
        <img src="../images/star.png" alt="star logo" />
        <span>5.0</span>
        <span>(6) • </span>
        <span>USA</span>
      </div>
      <p>Life Lessons with Katie Zaferes</p>
      <p>From $136 / person</p>
    </div>
  );
}
